from lxml import etree
import json

def load(filename):
    with open('config.xml') as f:
        data = f.read()

    root =  etree.XML(data)

    retObj = dict()
    
    retObj['user'] = str(root[0].findtext("user"))
    retObj['pass'] = str(root[1].findtext("pass"))
    retObj['host'] = str(root[2].findtext("host"))
    return retObj